func TestEnumMerchantStatus(t *testing.T) {
	t.Run("NewFromString_ACTIVE", func(t *testing.T) {
		t.Parallel()
		val, err := NewMerchantStatusFromString("ACTIVE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, MerchantStatus("ACTIVE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_INACTIVE", func(t *testing.T) {
		t.Parallel()
		val, err := NewMerchantStatusFromString("INACTIVE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, MerchantStatus("INACTIVE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewMerchantStatusFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewMerchantStatusFromString("ACTIVE")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

